import React, { useState, useEffect } from 'react';
import { Formula } from './types';
import { DEFAULT_FORMULAS } from './services/defaultData';
import TimerWidget from './components/TimerWidget';
import FormulaCard from './components/FormulaCard';
import CompletionModal from './components/CompletionModal';
import ReaderBar from './components/ReaderBar';
import { Heart, ArrowLeft, Wind } from 'lucide-react';

const STORAGE_KEY = 'nlg_formulas_v5_clean_reset_7';

const App: React.FC = () => {
  // --- STATE ---
  const [formulas, setFormulas] = useState<Formula[]>([]);
  const [view, setView] = useState<'grid' | 'detail'>('grid');
  const [selectedFormulaId, setSelectedFormulaId] = useState<string | null>(null);
  const [showCompletion, setShowCompletion] = useState(false);

  // --- EFFECTS ---

  // Load data
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setFormulas(JSON.parse(saved));
      } catch (e) {
        setFormulas(DEFAULT_FORMULAS);
      }
    } else {
      setFormulas(DEFAULT_FORMULAS);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(DEFAULT_FORMULAS));
    }
  }, []);

  // SCROLL FIX: Force scroll to top when view changes
  // This ensures Step 1 is visible immediately when opening a formula
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'instant' });
  }, [view, selectedFormulaId]);

  // --- HANDLERS ---

  const handleSelectFormula = (id: string) => {
    setSelectedFormulaId(id);
    setView('detail');
  };

  const handleBack = () => {
    setView('grid');
    setSelectedFormulaId(null);
  };

  const handleComplete = () => {
    setShowCompletion(true);
  };

  const selectedFormula = formulas.find(f => f.id === selectedFormulaId);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans selection:bg-pink-500/30">
      {/* Header */}
      <header className="fixed top-0 left-0 right-0 z-40 bg-slate-950/80 backdrop-blur-md border-b border-slate-800">
        <div className="max-w-4xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 text-pink-500">
            <Wind size={24} />
            <h1 className="text-xl font-bold tracking-tight text-white">NLG <span className="text-pink-500">Practice</span></h1>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="pt-24 pb-12 px-4 max-w-4xl mx-auto min-h-screen">
        {view === 'grid' ? (
          <div className="animate-fade-in">
            <div className="mb-8">
              <h2 className="text-3xl font-bold mb-2">Công thức Lớp 5.6</h2>
              <p className="text-slate-400">Chọn công thức để bắt đầu tập luyện hàng ngày.</p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {formulas.map(formula => (
                <FormulaCard 
                  key={formula.id} 
                  formula={formula} 
                  onClick={() => handleSelectFormula(formula.id)} 
                />
              ))}
            </div>
          </div>
        ) : (
          selectedFormula && (
            <div className="animate-fade-in space-y-6">
              {/* Nav Back */}
              <button 
                onClick={handleBack}
                className="flex items-center gap-2 text-slate-400 hover:text-pink-400 transition-colors mb-2 group"
              >
                <div className="p-1 rounded-full bg-slate-900 group-hover:bg-slate-800 border border-slate-800">
                  <ArrowLeft size={16} />
                </div>
                <span className="font-medium">Quay lại danh sách</span>
              </button>

              {/* Title Section */}
              <div>
                <h2 className="text-2xl md:text-3xl font-bold text-white mb-2 leading-tight">
                  {selectedFormula.title}
                </h2>
                <p className="text-slate-400 text-lg">{selectedFormula.subtitle}</p>
              </div>

              {/* Timer */}
              <TimerWidget 
                initialDuration={selectedFormula.durationSeconds}
                autoStart={false}
                onComplete={handleComplete}
              />

              {/* Reader Bar (Text-to-Speech) */}
              <ReaderBar textToRead={`${selectedFormula.title}. ${selectedFormula.steps.join('. ')}`} />

              {/* Steps List */}
              <div className="space-y-4">
                <div className="flex items-center gap-2 text-pink-300 font-medium mb-2">
                    <Heart size={20} className="text-pink-500" />
                    <span>Các bước thực hiện</span>
                </div>

                {selectedFormula.steps.map((step, index) => {
                  // Determine if step is a Note/Warning or a regular step
                  const isNote = step.toUpperCase().startsWith('LƯU Ý') || 
                                 step.toUpperCase().startsWith('CẢNH BÁO') || 
                                 step.toUpperCase().startsWith('***') ||
                                 step.trim().startsWith('•');

                  return (
                    <div 
                      key={index} 
                      className={`p-4 rounded-2xl border transition-all ${
                        isNote 
                          ? 'bg-amber-900/10 border-amber-500/30 text-amber-100/90' 
                          : 'bg-slate-900 border-slate-800 text-slate-200'
                      }`}
                    >
                      <div className="flex gap-4">
                        {!isNote && (
                          <div className="flex-shrink-0 w-8 h-8 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-pink-500 font-bold text-sm shadow-inner">
                            {index + 1}
                          </div>
                        )}
                        <div className={`leading-relaxed whitespace-pre-line ${isNote ? 'text-sm font-medium pl-1' : ''}`}>
                          {step}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )
        )}
      </main>

      {/* Completion Modal */}
      <CompletionModal 
        isOpen={showCompletion} 
        onClose={() => setShowCompletion(false)}
        title={selectedFormula?.title || ''}
      />
    </div>
  );
};

export default App;

