            <div className="flex items-center gap-2 text-stone-100 font-bold text-lg tracking-tight cursor-pointer" onClick={() => setView('grid')}>
              <div className="relative">
                 <div className="absolute inset-0 bg-pink-500 blur-lg opacity-40"></div>
                 <Heart className="text-pink-500 relative z-10 fill-pink-500/20" size={20} />
              </div>
              <span className="bg-clip-text text-transparent bg-gradient-to-r from-pink-400 to-rose-300">
                NLG Practice
              </span>
            </div>
          </div>

          <div className="flex items-center gap-3">
              <button
                onClick={() => setIsAdminMode(!isAdminMode)}
                className={`p-1.5 rounded-full transition-all ${isAdminMode ? 'text-pink-400 bg-pink-900/20' : 'text-slate-500 hover:text-slate-300'}`}
                title="Chế độ chỉnh sửa (Admin)"
              >
                <Settings size={18} />
              </button>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-grow overflow-y-auto scroll-smooth bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-900 via-slate-950 to-slate-950">
        <div className="max-w-4xl mx-auto min-h-full pb-10">

            {/* VIEW: GRID (Library) */}
            {view === 'grid' && (
              <div className="animate-fade-in p-6">
                <div className="text-center mb-8">
                  <h1 className="text-2xl font-bold text-slate-200 mb-2">Thư viện công thức</h1>
                  <p className="text-slate-500 text-sm">Chọn một công thức để bắt đầu thực hành.</p>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {formulas.map(formula => (
                    <FormulaCard 
                      key={formula.id} 
                      formula={formula} 
                      onClick={() => handleSelectFormula(formula.id)} 
                    />
                  ))}
                </div>
              </div>
            )}

            {/* VIEW: DETAIL (Practice) */}
            {view === 'detail' && currentFormula && (
              <div className="animate-fade-in flex flex-col">

                {/* Sticky Timer Section */}
                <div className="sticky top-0 z-20 bg-slate-950/95 backdrop-blur-xl border-b border-slate-800/50 shadow-2xl">
                   <div className="max-w-4xl mx-auto px-4 md:px-6 py-2">
                     <TimerWidget 
                       initialDuration={currentFormula.durationSeconds} 
                       autoStart={false} 
                       onComplete={handleTimerComplete}
                     />
                   </div>
                </div>

                {/* Info Section (Scrollable) */}
                <div className="p-4 md:p-6 space-y-6">
                  <div className="bg-slate-900/50 rounded-2xl p-4 md:p-8 border border-slate-800 shadow-xl relative">
                    {isAdminMode && (
                      <button 
                        onClick={handleEdit}
                        className="absolute top-4 right-4 p-2 bg-slate-800 hover:bg-pink-600 text-slate-400 hover:text-white rounded-lg transition-colors flex items-center gap-2 text-sm"
                      >
                        <Edit size={16} /> Sửa nội dung
                      </button>
                    )}

                    <h2 className="text-2xl md:text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-pink-200 to-slate-200 mb-2">
                      {currentFormula.title}
                    </h2>
                    <p className="text-pink-400/80 font-medium text-base md:text-lg mb-6 border-b border-white/5 pb-4">
                      {currentFormula.subtitle}
                    </p>

                    <div className="space-y-6">
                      <h3 className="text-lg font-semibold text-slate-200 uppercase tracking-wide">Hướng dẫn thực hiện:</h3>
                      {currentFormula.steps.map((step, idx) => {
                        const isWarning = step.startsWith('CẢNH BÁO');
                        const isNote = step.startsWith('LƯU Ý') || step.startsWith('***');

                        return (
                          <div key={idx} className={`flex gap-4 ${isWarning || isNote ? 'bg-slate-800/60 p-5 rounded-xl border border-white/5' : 'py-2'}`}>
                            {!isWarning && !isNote && (
                              <div className="flex-shrink-0 w-10 h-10 rounded-full bg-pink-900/30 text-pink-400 border border-pink-500/20 flex items-center justify-center font-bold text-lg shadow-inner mt-1">
                                {idx + 1}
                              </div>
                            )}
                            {/* LARGE TEXT SIZE APPLIED HERE */}
                            <p className={`leading-relaxed whitespace-pre-line ${
                              isWarning 
                                ? 'text-red-300 font-bold text-base md:text-lg' 
                                : (isNote 
                                    ? 'text-amber-200 font-medium text-base md:text-lg' 
                                    : 'text-slate-200 text-lg md:text-xl font-medium tracking-wide')
                            }`}>
                              {step}
                            </p>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>
              </div>
            )}

            {/* VIEW: EDIT (Admin) */}
            {view === 'edit' && currentFormula && (
              <div className="p-6">
                <FormulaEditor 
                  formula={currentFormula} 
                  onSave={handleSaveFormula} 
                  onCancel={() => setView('detail')} 
                />
              </div>
            )}

        </div>
      </main>

      {/* Completion Modal */}
      <CompletionModal 
        isOpen={showCompletion} 
        onClose={() => setShowCompletion(false)} 
        title={currentFormula?.title || ''} 
      />

    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, RotateCcw, Timer as TimerIcon, Bell } from 'lucide-react';

interface TimerWidgetProps {
  initialDuration?: number;
  autoStart?: boolean;
  onComplete?: () => void;
}

const TimerWidget: React.FC<TimerWidgetProps> = ({ initialDuration = 210, autoStart = false, onComplete }) => {
  const [timeLeft, setTimeLeft] = useState<number>(initialDuration);
  const [isActive, setIsActive] = useState(autoStart);
  const [totalTime, setTotalTime] = useState(initialDuration);
  const audioContextRef = useRef<AudioContext | null>(null);
  const wakeLockRef = useRef<any>(null); // Ref for Wake Lock

  // Update internal state when props change
  useEffect(() => {
    setTimeLeft(initialDuration);
    setTotalTime(initialDuration);
    if (autoStart) {
        setIsActive(true);
    } else {
        setIsActive(false);
    }
  }, [initialDuration, autoStart]);

  const presets = [
    { label: '1:30', seconds: 90 },
    { label: '3:30', seconds: 210 },
    { label: '5:30', seconds: 330 },
  ];

  // Initialize/Resume Audio Context (Must be done on user gesture)
  const initAudio = () => {
    if (!audioContextRef.current) {
      const Ctx = window.AudioContext || (window as any).webkitAudioContext;
      if (Ctx) {
        audioContextRef.current = new Ctx();
      }
    }
    if (audioContextRef.current && audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume().catch(err => console.error("Audio resume failed", err));
    }
  };

  const stopAudio = () => {
    if (audioContextRef.current && audioContextRef.current.state === 'running') {
      // Suspending the context stops all currently playing sounds immediately
      audioContextRef.current.suspend().catch(err => console.error("Audio suspend failed", err));
    }
  };

  // --- NOTIFICATION LOGIC ---
  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) return;

    if (Notification.permission === 'default') {
      await Notification.requestPermission();
    }
  };

  const sendNotification = () => {
    if (!('Notification' in window)) return;

    if (Notification.permission === 'granted') {
      try {
        // Close existing notification if any (optional logic, kept simple here)
        new Notification("NLG Practice", {
          body: "Đã hoàn thành thời gian tập!",
          requireInteraction: true, // Keeps notification on screen until user clicks
          silent: true // We already play our own sound
        });
      } catch (e) {
        console.error("Notification failed", e);
      }
    }
  };
  // --------------------------

  // --- WAKE LOCK LOGIC ---
  const requestWakeLock = async () => {
    try {
      if ('wakeLock' in navigator) {
        // Only request if not already active to avoid redundant calls
        if (!wakeLockRef.current) {
           wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
        }
      }
    } catch (err: any) {
      // Gracefully handle permission errors
      if (err.name !== 'NotAllowedError') {
        console.error(`Wake Lock error: ${err.name}, ${err.message}`);
      }
    }
  };

  const releaseWakeLock = async () => {
    if (wakeLockRef.current) {
      try {
        await wakeLockRef.current.release();
        wakeLockRef.current = null;
      } catch (err: any) {
        console.error(`Wake Lock release error: ${err.name}, ${err.message}`);
      }
    }
  };

  useEffect(() => {
    // Handle visibility change to re-acquire lock
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible' && isActive) {
        requestWakeLock();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);

    if (isActive) {
      requestWakeLock();
    } else {
      releaseWakeLock();
    }

    // Cleanup on unmount or when isActive changes
    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      releaseWakeLock();
    };
  }, [isActive]);
  // -----------------------

  // Play Cricket Sound using Web Audio API (Approx 6 seconds, Volume 30%)
  const playCricketSound = () => {
    try {
      if (!audioContextRef.current) {
         initAudio();
      }

      const ctx = audioContextRef.current;
      if (!ctx) return;

      const now = ctx.currentTime;

      // Helper to create a single pulse (part of a chirp)
      const playPulse = (time: number) => {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        // Cricket sound is typically high pitched (4000-5000Hz)
        osc.frequency.value = 4500; 
        osc.type = 'sine'; // Sine or triangle works well

        osc.connect(gain);
        gain.connect(ctx.destination);

        // Short envelope: Attack -> Decay
        gain.gain.setValueAtTime(0, time);
        // VOLUME 30% (0.3)
        gain.gain.linearRampToValueAtTime(0.3, time + 0.01); // Quick attack
        gain.gain.linearRampToValueAtTime(0, time + 0.04); // Quick decay

        osc.start(time);
        osc.stop(time + 0.05);
      };

      // Create a "Chirp" (a trill of multiple pulses)
      const playChirp = (startTime: number) => {
         // A chirp consists of ~3-5 pulses in quick succession
         for(let i = 0; i < 4; i++) {
             playPulse(startTime + (i * 0.05)); // 50ms spacing
         }
      };

      // Play pattern: Chirps spaced 0.7s apart
      // Extended to cover ~6 seconds
      const intervals = [0, 0.7, 1.4, 2.1, 2.8, 3.5, 4.2, 4.9, 5.6];
      intervals.forEach(timeOffset => playChirp(now + timeOffset));

    } catch (e) {
      console.error("Audio play error", e);
    }
  };

  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => {
            if (prev <= 1) {
                // Timer finished
                setIsActive(false);
                playCricketSound(); // Cricket sound
                sendNotification(); // Send Browser Notification
                if (onComplete) onComplete();
                return 0;
            }
            return prev - 1;
        });
      }, 1000);
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, onComplete]);

  const toggleTimer = () => {
    if (!isActive) {
      stopAudio(); // Stop any lingering sound from previous run
      initAudio(); // Initialize audio on start
      requestNotificationPermission(); // Ask for permission on user interaction
    } else {
      stopAudio(); // Silence if pausing
    }
    setIsActive(!isActive);
  };

  const resetTimer = () => {
    stopAudio(); // Stop sound immediately on reset
    setIsActive(false);
    setTimeLeft(totalTime);
  };

  const setManualPreset = (seconds: number) => {
    stopAudio(); // Stop sound on preset change
    setTotalTime(seconds);
    setTimeLeft(seconds);
    setIsActive(false);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const progress = totalTime > 0 ? ((totalTime - timeLeft) / totalTime) * 100 : 0;

  return (
    <div className="bg-slate-900/60 backdrop-blur-sm border border-rose-900/30 rounded-2xl p-5 mb-6 shadow-2xl relative overflow-hidden">
      {/* Decorative gradient blob */}
      <div className="absolute -top-10 -right-10 w-40 h-40 bg-pink-600/10 rounded-full blur-3xl pointer-events-none"></div>

      <div className="flex items-center justify-between mb-4 text-pink-300 font-medium relative z-10">
        <div className="flex items-center gap-2">
            <TimerIcon size={20} className="text-pink-400" />
            <span>Thời gian thực hiện</span>
        </div>

        {/* Notification Permission Indicator (Optional visual cue) */}
        {'Notification' in window && Notification.permission === 'granted' && (
            <div className="flex items-center gap-1 text-xs text-emerald-400 bg-emerald-900/30 px-2 py-1 rounded-full border border-emerald-500/20">
                <Bell size={10} />
                <span>Đã bật thông báo</span>
            </div>
        )}
      </div>

      <div className="flex flex-col md:flex-row items-center justify-between gap-8 relative z-10">
        {/* Timer Display */}
        <div className="relative flex items-center justify-center flex-shrink-0">
             {/* Progress Ring Background */}
             <svg className="w-32 h-32 transform -rotate-90">
                <circle
                  cx="64"
                  cy="64"
                  r="58"
                  stroke="currentColor"
                  strokeWidth="8"
                  fill="transparent"
                  className="text-slate-800"
                />
                <circle
                  cx="64"
                  cy="64"
                  r="58"
                  stroke="currentColor"
                  strokeWidth="8"
                  fill="transparent"
                  strokeDasharray={364}
                  strokeDashoffset={364 - (364 * progress) / 100}
                  strokeLinecap="round"
                  className={`text-pink-500 transition-all duration-1000 ease-linear ${isActive ? 'opacity-100' : 'opacity-80'}`}
                />
              </svg>
              <div className="absolute flex flex-col items-center">
                <span className="text-4xl font-bold text-white tabular-nums tracking-wider">
                  {formatTime(timeLeft)}
                </span>
                <span className="text-xs text-slate-500 mt-1 uppercase tracking-widest font-semibold">Còn lại</span>
              </div>
        </div>

        {/* Controls */}
        <div className="flex flex-col gap-4 w-full md:w-auto flex-1">
          {/* Presets */}
          <div className="grid grid-cols-3 gap-2">
            {presets.map((preset) => (
              <button
                key={preset.label}
                onClick={() => setManualPreset(preset.seconds)}
                className={`py-2 px-1 text-sm rounded-xl font-semibold transition-all duration-200 border ${
                  totalTime === preset.seconds
                    ? 'bg-pink-600 text-white border-pink-500 shadow-lg shadow-pink-900/50 scale-105'
                    : 'bg-slate-800/80 text-slate-400 border-slate-700 hover:border-pink-500/50 hover:text-pink-200'
                }`}
              >
                {preset.label}
              </button>
            ))}
          </div>

          {/* Play/Pause/Reset */}
          <div className="flex gap-3">
            <button
              onClick={toggleTimer}
              className={`flex-1 flex items-center justify-center gap-2 px-6 py-3 rounded-full text-white font-bold transition-all shadow-lg active:scale-95 ${
                isActive 
                  ? 'bg-orange-500 hover:bg-orange-400 shadow-orange-900/20' 
                  : 'bg-pink-600 hover:bg-pink-500 shadow-pink-900/30'
              }`}
            >
              {isActive ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" />}
              {isActive ? 'Tạm dừng' : 'Bắt đầu'}
            </button>
            <button
              onClick={resetTimer}
              className="p-3 rounded-full bg-slate-800 text-slate-400 border border-slate-700 hover:bg-slate-700 hover:text-white transition-colors"
              title="Đặt lại"
            >
              <RotateCcw size={18} />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TimerWidget;
